import React, { useState } from 'react';
import './Game.css'; 

function Game() {
    const [size, setSize] = useState(100);

    const handleClick = () => {
        setSize(size === 100 ? 150 : 100);
    };

    return (
        <div
            className="square"
            onClick={handleClick}
            style={{
                width: `1800px`,
                height: `800px`,
            }}
        ></div>
    );
}

export default Game;
